import collections
from typing import Any, Deque, Dict, List, Optional, Tuple, Set

# --- UTILITY FUNCTION 1: Binary Tree Level-Order Traversal ---

class TreeNode:
    """Definition for a binary tree node.
    This class is typically provided in competitive programming problems or
    is a standard building block for tree-related algorithms.
    """
    def __init__(self, val: Any = 0, left: Optional['TreeNode'] = None, right: Optional['TreeNode'] = None):
        self.val = val
        self.left = left
        self.right = right

def level_order_traversal(root: Optional[TreeNode]) -> List[List[Any]]:
    """
    Performs a level-order (Breadth-First Search) traversal of a binary tree.

    This function is extremely useful for:
    - Serializing/deserializing trees.
    - Solving problems that require processing nodes level by level (e.g., finding the
      maximum value in each level, connecting nodes at the same level, etc.).

    Args:
        root: The root node of the binary tree. Can be None for an empty tree.

    Returns:
        A list of lists, where each inner list contains the values of nodes
        at a particular level, ordered from root to leaves, and from left to right
        within each level. Returns an empty list if the tree is empty.
    """
    if not root:
        return []

    result: List[List[Any]] = []
    queue: Deque[TreeNode] = collections.deque([root])

    while queue:
        level_size = len(queue)
        current_level_values: List[Any] = []
        for _ in range(level_size):
            node = queue.popleft()
            current_level_values.append(node.val)

            if node.left:
                queue.append(node.left)
            if node.right:
                queue.append(node.right)
        result.append(current_level_values)

    return result

