# --- UTILITY FUNCTION 2: Graph Shortest Path BFS (Unweighted) ---

def bfs_shortest_path(
    graph: Dict[Any, List[Any]],
    start_node: Any
) -> Tuple[Dict[Any, int], Dict[Any, Optional[Any]]]:
    """
    Performs a Breadth-First Search (BFS) to find the shortest distance and
    predecessor path from a given start node in an unweighted graph.

    This function is extremely useful for:
    - Finding the minimum number of edges to reach any node from a source.
    - Detecting reachability between nodes.
    - Reconstructing a shortest path.
    - Solving various graph problems like shortest path in a maze, connected components,
      or flood fill, where edge weights are uniform (or absent).

    Args:
        graph: An adjacency list representation of the graph. Keys are nodes,
               values are lists of neighboring nodes. Nodes must be hashable.
               Assumes undirected graph if (u, v) implies (v, u) in adjacency lists,
               or directed if only (u, v) is present.
        start_node: The node from which to start the BFS. It must be a hashable type.

    Returns:
        A tuple containing two dictionaries:
        1. distances: Maps each reachable node to its shortest distance (number of edges)
           from the start_node. Nodes not reachable from start_node will not be in this dictionary.
        2. predecessors: Maps each reachable node (except start_node itself) to its direct
           predecessor node on one of the shortest paths from start_node. This can be used
           to reconstruct the path. The start_node will map to None.
           If a node is unreachable, it will not be in this dictionary.
    """
    distances: Dict[Any, int] = {}
    predecessors: Dict[Any, Optional[Any]] = {}
    queue: Deque[Any] = collections.deque()

    # Initialize for the start node
    if start_node in graph or any(start_node in neighbors for neighbors in graph.values()):
        # Only add to queue if start_node is a known node in the graph,
        # either as a key or as a neighbor.
        distances[start_node] = 0
        predecessors[start_node] = None
        queue.append(start_node)
    else:
        # If start_node is not part of the graph at all, it's an isolated component of size 1.
        return {start_node: 0}, {start_node: None}

    while queue:
        current_node = queue.popleft()

        # Iterate over neighbors. graph.get handles cases where current_node might be
        # a sink node (no outgoing edges) or an isolated node defined only as a neighbor.
        for neighbor in graph.get(current_node, []):
            if neighbor not in distances: # Check if the neighbor has been visited/processed
                distances[neighbor] = distances[current_node] + 1
                predecessors[neighbor] = current_node
                queue.append(neighbor)

    return distances, predecessors

